                  animate={isActive ? { opacity: 1, y: 0 } : {}}
                  transition={{ delay: index * 0.05, duration: 0.5 }}
                  className="group relative p-3 md:p-6 border border-white/10 hover:border-primary/50 transition-all duration-300 bg-[#0a0f1d]/50 backdrop-blur-3xl rounded-xl md:rounded-2xl flex flex-col shadow-lg"
                >
                  <div className="flex items-center gap-3 md:gap-4 mb-2 md:mb-3">
                    <div className="p-1.5 md:p-2.5 rounded-lg md:rounded-xl bg-primary/10 border border-primary/20 group-hover:bg-primary transition-all duration-500">
                      <Icon size={14} className="text-primary group-hover:text-white md:size-4" />
                    </div>
                    <h3 className="text-xs md:text-lg font-bold tracking-tight text-white leading-none">
                      {item.title}
