  backgroundImage?: string;
}

const TechDataParticles: React.FC = () => {
  const particles = useMemo(() => Array.from({ length: 15 }).map((_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    size: Math.random() * 2 + 1,
    duration: Math.random() * 10 + 10,
    delay: Math.random() * 5
  })), []);

  return (
    <div className="absolute inset-0 z-[5] pointer-events-none overflow-hidden opacity-10">
      {particles.map((p) => (
        <motion.div
          key={p.id}
          initial={{ x: `${p.x}%`, y: `${p.y}%`, opacity: 0 }}
          animate={{ y: [`${p.y}%`, `${p.y - 10}%`], opacity: [0, 1, 0] }}
          transition={{ duration: p.duration, repeat: Infinity, delay: p.delay, ease: "linear" }}
          className="absolute bg-primary rounded-full"
          style={{ width: p.size, height: p.size, filter: 'blur(1px)' }}
        />
      ))}
    </div>
  );
};

const ExpertiseSection: React.FC<ExpertiseSectionProps> = ({ isActive, title, items = [], backgroundImage }) => {
