  })), []);

  return (
    <div className="absolute inset-0 z-[2] overflow-hidden pointer-events-none opacity-30">
      {elements.map((el) => (
        <motion.div
          key={el.id}
          initial={{ opacity: 0, x: `${el.x}%`, y: `${el.y}%` }}
          animate={{
            opacity: [0, 0.4, 0],
            y: [`${el.y}%`, `${el.y - 15}%`],
          }}
          transition={{
            duration: el.duration,
            repeat: Infinity,
            ease: "linear",
            delay: el.id * 0.4
          }}
          className="absolute font-mono text-primary text-[10px] font-bold"
        >
          {el.char}
        </motion.div>
      ))}
    </div>
  );
};

export const BrandingSeal = () => (
  <motion.span 
    initial={{ opacity: 0.5, scale: 0.8 }}
    animate={{ 
      opacity: [0.6, 1, 0.6],
      scale: [1, 1.2, 1],
    }}
    transition={{
      duration: 3,
      repeat: Infinity,
      ease: "easeInOut"
    }}
    className="inline-block w-[0.16em] h-[0.16em] bg-primary rounded-full ml-[0.15em] mb-[0.05em] align-baseline shadow-[0_0_15px_rgba(59,130,246,0.8)] flex-shrink-0" 
  />
);

const Section: React.FC<SectionProps> = ({ 
  isActive, 
  subtitle, 
  title, 
  content, 
  showButton, 
  buttonText, 
  backgroundImage,
  id 
}) => {
  const [isLoaded, setIsLoaded] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);
  const isHero = id === 'hero';

  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ["start end", "end start"]
  });

  const backgroundY = useTransform(scrollYProgress, [0, 1], ["-10%", "10%"]);

  useEffect(() => {
    if (backgroundImage) {
      const img = new Image();
      img.src = backgroundImage;
      img.onload = () => setIsLoaded(true);
      img.onerror = () => setIsLoaded(true);
    } else {
      setIsLoaded(true);
    }
  }, [backgroundImage]);

  return (
    <section 
      id={id} 
      ref={sectionRef}
      className="relative h-[100dvh] w-full snap-child flex flex-col justify-center overflow-hidden bg-surface"
    >
      <div className="absolute inset-0 z-0 overflow-hidden">
        <AnimatePresence mode="wait">
          {backgroundImage && isLoaded && (
            <motion.div 
              key={backgroundImage}
              initial={{ opacity: 0, scale: 1.1 }}
              animate={isActive ? { 
                opacity: isHero ? 0.65 : 0.5, 
                scale: 1 
              } : { opacity: 0, scale: 1.1 }}
              exit={{ opacity: 0 }}
              transition={{ duration: 1.2, ease: [0.22, 1, 0.36, 1] }}
              className="absolute inset-0 z-0 bg-cover bg-center"
              style={{ 
                y: backgroundY, 
                backgroundImage: `url(${backgroundImage})`,
                filter: isHero ? 'brightness(0.9) contrast(1.1) saturate(1.2)' : 'brightness(0.7)'
              }}
            />
          )}
        </AnimatePresence>

        {isHero && <TechBackgroundLayer />}

        <div className="absolute inset-0 z-[3] pointer-events-none">
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-surface/80 via-transparent to-surface/80 opacity-90" />
          <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-r from-surface via-surface/30 to-transparent" />
        </div>
      </div>

      <div className="relative z-10 px-6 md:px-20 lg:px-32 max-w-7xl w-full mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={isActive ? { opacity: 1, y: 0 } : { opacity: 0, y: 30 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
        >
          {subtitle && <div className="mb-2">{subtitle}</div>}

          <h1 className="text-4xl md:text-5xl lg:text-7xl xl:text-8xl font-heading font-extrabold tracking-[-0.06em] mb-6 md:mb-8 text-white leading-[0.9] flex items-baseline">
            {title}<BrandingSeal />
          </h1>

          {content && (
            <p className="text-sm md:text-lg lg:text-xl text-white/70 max-w-2xl leading-[1.6] mb-8 md:mb-12 font-medium tracking-tight">
              {content}
            </p>
          )}

          {showButton && (
            <motion.button 
              whileHover={{ scale: 1.02 }}
              whileTap={{ scale: 0.98 }}
              className="group bg-primary text-white font-bold py-4 px-10 md:py-6 md:px-16 rounded-xl flex items-center justify-center gap-4 transition-all shadow-xl shadow-primary/20 w-fit"
            >
              <span className="text-[10px] md:text-[11px] uppercase tracking-[0.3em] font-black">{buttonText}</span>
              <ArrowRight size={20} className="group-hover:translate-x-2 transition-transform" />
            </motion.button>
          )}
        </motion.div>
      </div>

      {isHero && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={isActive ? { opacity: 0.8 } : {}}
          className="absolute bottom-10 left-6 md:left-20 lg:left-32 flex flex-col items-center gap-3 cursor-pointer group"
          onClick={() => {
             const container = document.querySelector('.snap-container');
             if (container) {
               container.scrollBy({ top: window.innerHeight, behavior: 'smooth' });
             }
          }}
        >
          <motion.span 
            whileHover={{ y: -2, color: '#3b82f6' }}
            className="font-mono text-[8px] tracking-[0.5em] uppercase font-black text-white/50 transition-colors"
          >
            SCROLL
          </motion.span>
          <div className="w-[1px] h-12 bg-white/10 relative overflow-hidden">
            <motion.div 
              animate={{ y: ['-100%', '100%'] }}
              transition={{ duration: 1.5, repeat: Infinity, ease: "easeInOut" }}
              className="absolute top-0 left-0 w-full h-1/2 bg-primary"
            />
          </div>
        </motion.div>
      )}
    </section>
  );
};

